public class ByteProcess
{
    public List<byte> buffer = new List<byte>();

    // Add a byte array to the internal buffer
    public void Add(byte[] data)
    {
        if (data == null || data.Length == 0)
            return;

        // Compute checksum (sum of all bytes modulo 65536)
        ushort sum = 0;
        foreach (byte b in data)
            sum += b;

        // Write checksum to buffer (little-endian)
        buffer.Add((byte)(sum & 0xFF));
        buffer.Add((byte)(sum >> 8));

        // Write actual data
        buffer.AddRange(data);
    }


    // Generate final 32-byte AES key
    public byte[] Generate()
    {
        if (buffer.Count == 0)
            throw new InvalidOperationException("No data added to ByteProcess.");
        byte[] data = new byte[0x100];

        int copyLength = Math.Min(buffer.Count, 0x100);
        buffer.CopyTo(0, data, 0, copyLength);
        using (var sha512 = SHA512.Create())
        {
            byte[] hash512 = sha512.ComputeHash(data);
            using (var sha256 = SHA256.Create())
            {
                return sha256.ComputeHash(hash512);
            }
        }
    }
    public void Clear()
    {
        buffer.Clear();
    }
}
