public static class StringExtensions
{
    public static int GetLegacyNonRandomizedHashCode(this string str)
    {
        if (str == null)
            throw new ArgumentNullException(nameof(str));

        int n5381 = 5381;
        int n5381_1 = 5381;
        int i = 0;
        int len = str.Length;

        if (len > 0)
        {
            while (true)
            {
                n5381 = str[i] ^ (33 * n5381);

                i++;
                if (i >= len) break;

                n5381_1 = str[i] ^ (33 * n5381_1);

                i++;
                if (i >= len) break;
            }
        }
        return n5381 + 1566083941 * n5381_1;
    }
}
